import React from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import { estadoConfig, ventasSemana } from '../datos';

function StatCard({ label, value, color, sub }) {
  return (
    <div style={{ background:'#fff', borderRadius:12, padding:'1rem 1.25rem', flex:1, minWidth:140 }}>
      <div style={{ fontSize:13, color:'#64748B', marginBottom:6 }}>{label}</div>
      <div style={{ fontSize:26, fontWeight:700, color: color||'#1E293B' }}>{value}</div>
      {sub && <div style={{ fontSize:12, color:'#94A3B8', marginTop:4 }}>{sub}</div>}
    </div>
  );
}

export default function Dashboard({ pedidos, setPagina }) {
  const hoy = pedidos.filter(p => p.estado !== 'entregado');
  const ingresos = pedidos.filter(p=>p.estado==='entregado').reduce((s,p)=>s+p.productos.reduce((a,x)=>a+x.cant*x.precio,0),0);
  const enPrep = pedidos.filter(p=>p.estado==='preparacion').length;
  const nuevos = pedidos.filter(p=>p.estado==='nuevo').length;

  return (
    <div style={{ padding:'1.5rem' }}>
      <h1 style={{ fontSize:20, fontWeight:700, marginBottom:'1.25rem' }}>Panel principal</h1>

      <div style={{ display:'flex', gap:12, marginBottom:'1.5rem', flexWrap:'wrap' }}>
        <StatCard label="Pedidos activos" value={hoy.length} sub="sin entregar aún" />
        <StatCard label="Pedidos nuevos" value={nuevos} color="#F59E0B" sub="esperando atención" />
        <StatCard label="En preparación" value={enPrep} color="#3B82F6" sub="en cocina/preparando" />
        <StatCard label="Ingresos entregados" value={`Bs. ${ingresos}`} color="#10B981" sub="cobrados hoy" />
      </div>

      <div style={{ display:'grid', gridTemplateColumns:'1fr 300px', gap:12 }}>
        <div style={{ background:'#fff', borderRadius:12, padding:'1.25rem' }}>
          <div style={{ fontWeight:600, marginBottom:'1rem' }}>Pedidos esta semana</div>
          <ResponsiveContainer width="100%" height={220}>
            <BarChart data={ventasSemana}>
              <XAxis dataKey="dia" tick={{ fontSize:12 }} />
              <YAxis tick={{ fontSize:12 }} />
              <Tooltip />
              <Bar dataKey="pedidos" fill="#2563EB" radius={[4,4,0,0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div style={{ background:'#fff', borderRadius:12, padding:'1.25rem' }}>
          <div style={{ fontWeight:600, marginBottom:'1rem' }}>Últimos pedidos</div>
          <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
            {pedidos.slice(0,5).map(p => {
              const cfg = estadoConfig[p.estado];
              const total = p.productos.reduce((s,x)=>s+x.cant*x.precio,0);
              return (
                <div key={p.id} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 0', borderBottom:'1px solid #F1F5F9' }}>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:13, fontWeight:500 }}>{p.cliente}</div>
                    <div style={{ fontSize:12, color:'#94A3B8' }}>{p.id} · {p.hora}</div>
                  </div>
                  <span style={{ background:cfg.bg, color:cfg.color, fontSize:11, padding:'3px 8px', borderRadius:99, fontWeight:500 }}>{cfg.label}</span>
                  <div style={{ fontSize:13, fontWeight:600 }}>Bs. {total}</div>
                </div>
              );
            })}
          </div>
          <button onClick={()=>setPagina('pedidos')} style={{ marginTop:'1rem', width:'100%', padding:'8px', borderRadius:8, border:'1px solid #E2E8F0', background:'transparent', cursor:'pointer', fontSize:13, color:'#2563EB' }}>
            Ver todos los pedidos →
          </button>
        </div>
      </div>
    </div>
  );
}
